INSERT INTO `app` VALUES (393219349504102400,'创建一个个体的团队介绍静态网站。色系：活力橙蓝(#0277b','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/22/b7782daf5097452e9712cc8613d329cc.jpg','创建一个个体的团队介绍静态网站。色系：活力橙蓝(#0277bd+#ff6f00)，布局：网格卡片。包含团队愿景Banner、成员卡片网格（含头像占位、姓名、职位、简介）、团队文化价值观、团队数据展示（成员数量、项目经验等）、加入我们招聘区、联系方式。页面需有成员卡片悬浮和滚动渐入动效。所有内容使用真实可信的团队场景文本。\n\n网站需要展示的具体内容：添加模拟数据即可。','multi_file','workflow','tysYeIbX','2026-03-22 14:58:50',99,390705603766513664,'2026-03-27 19:52:12','2026-03-22 14:54:18','2026-03-27 19:52:11',0),(393221828492955648,'创建一个个体的在线个人简历静态网站。色系：商务蓝(#1565','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/22/6e609cc9cdd24e9e8381d2b0b8dc84db.jpg','创建一个个体的在线个人简历静态网站。色系：商务蓝(#1565c0+#e3f2fd)，布局：单栏居中。包含个人照片与基本信息区、工作经历时间线、教育背景、技能评分条（纯CSS动效）、项目经验卡片、联系方式区域。页面需有滚动渐入和进度条加载动效。所有内容使用真实可信的示例文本。\n网站需要展示的具体内容：添加模拟数据即可。','single_html','workflow','Y3PowI3s','2026-03-22 15:11:44',99,390705603766513664,'2026-03-22 16:33:50','2026-03-22 15:04:09','2026-03-22 16:33:50',0),(393222100686508032,'创建一个个体的活动宣传静态网站。色系：活力橙红(#e6510','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/22/6b05eb5b7cec4d55b34f8422110464f0.jpg','创建一个个体的活动宣传静态网站。色系：活力橙红(#e65100+#fff3e0)，布局：全屏模块滚动。包含活动主题全屏Banner、活动倒计时器（纯JS实现实时倒计时）、活动日程时间表、嘉宾/组织者介绍卡片、往期活动数据回顾（参与人数等数字动效）、报名表单（仅UI无后端）。请为活动设计一个主题 LOGO。页面需有倒计时翻牌和模块渐入动效。所有内容使用真实可信的活动场景文本。\n\n网站需要展示的具体内容：活动主题是山东天泽公司春游活动通知页，数据模拟即可。\n\n基于VUE。','vue_project','workflow','RzsM2grt','2026-03-22 15:11:48',99,390705603766513664,'2026-03-25 19:51:42','2026-03-22 15:05:14','2026-03-25 19:51:41',0),(394027647220396032,'创建一个面向学生的、响应式的人工智能科普宣传网站，包含首页介','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/25/0f9d875749624b16a1c7002e6a2137ba.jpg','创建一个面向学生的、响应式的人工智能科普宣传网站，包含首页介绍、AI领域概览（如机器学习、计算机视觉、自然语言处理等）、学习资源推荐、趣味互动示例（如简单AI体验小工具）等内容；网站需设计一个原创、简洁现代的专属LOGO，体现人工智能与教育融合的主题（如融入大脑、齿轮、代码、学生剪影等元素），LOGO需适配网页顶部导航栏及移动端显示，并支持高清导出。','vue_project','workflow','HBPBFZa2','2026-03-25 19:49:24',99,390705603766513664,'2026-03-25 18:17:01','2026-03-24 20:26:11','2026-03-25 19:49:40',0),(395002924146741248,'创建一个网页，用于我给我的老板总结本周工作成果。\n成果包含：','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/27/db5fa90688284e319fb2cfacfb98a343.jpg','创建一个网页，用于我给我的老板总结本周工作成果。\n成果包含：\n本周我完成了以下内容——\n主导了618大促预售活动策划，完成目标销售额1200万，超预期15%。\n\n优化了广告投放策略，ROI提升至3.2，点击率提升20%。\n\n上线了“会员日”新玩法，会员复购率环比提升8%。\n\n推动与3家头部KOL达成合作，带来新增用户5万人。\n\n完成了首页改版，重点品类曝光提升25%。\n\n团队培训两场，提升客服转化率10%等。\n\n完成了竞争对手分析报告，制定了下阶段的定价策略。\n\n协调供应链，确保爆款库存充足，售罄率控制在90%。','single_html','workflow','N8wOs9F5','2026-03-27 19:52:21',99,390705603766513664,'2026-03-27 19:52:13','2026-03-27 13:01:35','2026-03-27 19:52:36',0),(395426007491915776,'我要向我的男朋友杜瑞持求婚','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','我要向我的男朋友杜瑞持求婚','ai_strategy','workflow',NULL,NULL,0,390705603766513664,'2026-03-28 17:02:46','2026-03-28 17:02:46','2026-03-28 17:03:34',1),(395426299868356608,'为向男朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/28/8a329d459c6e4ff8a3244cbb5d07b6be.jpg','为向男朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态网站，包含以下核心内容：  \n- 首页以大图轮播或全屏视频背景呈现两人珍贵合影与回忆片段（支持图片/视频占位）；  \n- “我们的故事”页面，按时间线展示相识、相知、相爱的重要节点（可配文字+照片）；  \n- “为什么是我？”或“致杜瑞持”专属信件页面，用真挚文字表达爱意与承诺；  \n- 求婚倒计时模块（可选固定日期或点击触发倒计时）；  \n- 互动环节：如点击爱心/戒指图标触发动画、轻触屏幕浮现告白语句、或隐藏式“YES”按钮（点击后弹出求婚成功动效与祝福语）；  \n- 全站采用柔和色调（如暖粉、香槟金、浅灰），字体优雅易读，动效细腻克制，适配手机与桌面端；  \n- 页面底部可署名“From [你的名字] · 永远爱你”。  \n（注：网站为纯静态部署，不涉及用户登录、数据提交或后端存储）','vue_project','agent','4HB20oI1','2026-03-28 17:10:40',0,390705603766513664,'2026-03-28 17:03:56','2026-03-28 17:03:56','2026-03-29 11:19:30',1),(395702039918698496,'为向男朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','为向男朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态网站，包含以下核心内容： - 首页以大图轮播或全屏视频背景呈现两人珍贵合影与回忆片段（支持图片/视频占位）； - “我们的故事”页面，按时间线展示相识、相知、相爱的重要节点（可配文字+照片）； - “为什么是我？”或“致杜瑞持”专属信件页面，用真挚文字表达爱意与承诺； - 求婚倒计时模块（可选固定日期或点击触发倒计时）； - 互动环节：如点击爱心/戒指图标触发动画、轻触屏幕浮现告白语句、或隐藏式“YES”按钮（点击后弹出求婚成功动效与祝福语）； - 全站采用柔和色调（如暖粉、香槟金、浅灰），字体优雅易读，动效细腻克制，适配手机与桌面端； - 页面底部可署名“From [你的名字] · 永远爱你”。 （注：网站为纯静态部署，不涉及用户登录、数据提交或后端存储）','vue_project','agent',NULL,NULL,0,390705603766513664,'2026-03-29 11:19:38','2026-03-29 11:19:38','2026-03-29 11:30:29',1),(395704799699517440,'为向男朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','为向男朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态网站，包含以下核心内容： - 首页以大图轮播或全屏视频背景呈现两人珍贵合影与回忆片段（支持图片/视频占位）； - “我们的故事”页面，按时间线展示相识、相知、相爱的重要节点（可配文字+照片）； - “为什么是我？”或“致杜瑞持”专属信件页面，用真挚文字表达爱意与承诺； - 求婚倒计时模块（可选固定日期或点击触发倒计时）； - 互动环节：如点击爱心/戒指图标触发动画、轻触屏幕浮现告白语句、或隐藏式“YES”按钮（点击后弹出求婚成功动效与祝福语）； - 全站采用柔和色调（如暖粉、香槟金、浅灰），字体优雅易读，动效细腻克制，适配手机与桌面端； - 页面底部可署名“From [你的名字] · 永远爱你”。 （注：网站为纯静态部署，不涉及用户登录、数据提交或后端存储）','vue_project','agent',NULL,NULL,0,390705603766513664,'2026-03-29 11:30:36','2026-03-29 11:30:36','2026-03-29 11:32:43',1),(395705664237858816,'我叫张宏倩，我要向女朋友杜瑞持求婚，设计一个浪漫、温馨、个性','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','我叫张宏倩，我要向女朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态网站，包含以下核心内容： - 首页以大图轮播或全屏视频背景呈现两人珍贵合影与回忆片段（支持图片/视频占位）； - “我们的故事”页面，按时间线展示相识、相知、相爱的重要节点（可配文字+照片）； - “为什么是我？”或“致杜瑞持”专属信件页面，用真挚文字表达爱意与承诺； - 求婚倒计时模块（可选固定日期或点击触发倒计时）； - 互动环节：如点击爱心/戒指图标触发动画、轻触屏幕浮现告白语句、或隐藏式“YES”按钮（点击后弹出求婚成功动效与祝福语）； - 全站采用柔和色调（如暖粉、香槟金、浅灰），字体优雅易读，动效细腻克制，适配手机与桌面端； - 页面底部可署名“From [你的名字] · 永远爱你”。 （注：网站为纯静态部署，不涉及用户登录、数据提交或后端存储）','vue_project','agent',NULL,NULL,0,390705603766513664,'2026-03-29 11:34:02','2026-03-29 11:34:02','2026-03-29 11:59:40',1),(395712139727241216,'我叫张宏倩，我要向女朋友杜瑞持求婚，设计一个浪漫、温馨、个性','https://rich-tams.oss-cn-beijing.aliyuncs.com/logo.png','我叫张宏倩，我要向女朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态网站','vue_project','agent',NULL,NULL,0,390705603766513664,'2026-03-29 11:59:46','2026-03-29 11:59:46','2026-03-29 12:32:22',1),(395720848251678720,'我叫张宏倩，我要向女朋友杜瑞持求婚，设计一个浪漫、温馨、个性','https://rich-tams.oss-cn-beijing.aliyuncs.com/richcodeweaver/2026/03/29/524cd5485b49421bb978ec9e85b8b87d.jpg','我叫张宏倩，我要向女朋友杜瑞持求婚，设计一个浪漫、温馨、个性化的响应式静态网站','vue_project','agent','8BYYM4Du','2026-03-29 13:03:32',0,390705603766513664,'2026-03-29 12:34:22','2026-03-29 12:34:22','2026-03-29 13:03:43',0