CREATE TABLE `rag_param` (
  `id` bigint NOT NULL COMMENT 'id（雪花）',
  `param_key` varchar(64) NOT NULL COMMENT '参数键（唯一标识，代码中使用）',
  `param_name` varchar(128) NOT NULL COMMENT '参数名称（中文，供管理界面展示）',
  `param_value` text NOT NULL COMMENT '参数值（统一以字符串存储，按 param_type 转换）',
  `param_type` varchar(16) NOT NULL COMMENT '参数类型：int / double / textarea',
  `param_group` varchar(64) NOT NULL COMMENT '参数分组：etl / retrieval / injection',
  `description` varchar(512) DEFAULT NULL COMMENT '参数描述（用途说明）',
  `sort_order` int NOT NULL DEFAULT '0' COMMENT '排序（越小越靠前）',
  `create_time` datetime DEFAULT NULL COMMENT '创建时间',
  `update_time` datetime DEFAULT NULL COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `param_key` (`param_key`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='RAG 参数配置表';
